let uptimeOutput = msg.payload.toString();
// Wir suchen die Zahl direkt nach "load average:"
let match = uptimeOutput.match(/load average: ([\d.]+)/);

if (match) {
    let load = parseFloat(match[1]);

    // Umrechnung auf Prozent: 
    // Load 8.0 = 100% bei 8 Kernen.
    let prozent = (load / 8) * 100;

    // Wir runden auf 1 Nachkommastelle
    msg.payload = Number(prozent.toFixed(1));

    // Optional: Ein Topic setzen, damit der Chart weiß, was was ist
    msg.topic = "CPU-Last";

    return msg;
}

try {
