    ]
};

return [msgBar, msgTable];

let lines = msg.payload.trim().split("\n");
// Wir suchen die Zeile, die mit "Mem:" beginnt
let memLine = lines.find(l => l.startsWith("Mem:")).split(/\s+/);

// Spaltenzuordnung bei 'free -m':
// [0] = "Mem:", [1] = total, [2] = used, [3] = free
