let usedMB = parseInt(memLine[2]);
let freeMB = parseInt(memLine[3]);

let totalGB = (totalMB / 1024).toFixed(1);
let usedGB = (usedMB / 1024).toFixed(1);
let freeGB = (freeMB / 1024).toFixed(1);

